export function getDailyStudy(reference: string): BibleStudyData | null {
  // Extract "Book Chapter" from reference like "Philippians 4:13"
  const parts = reference.split(":");
  const chapterRef = parts[0]; // e.g., "Philippians 4"
  return bibleStudyChapters[chapterRef] || null;
}
